REQUIRED = {'case_id', 'holdout', 'rubric_levels', 'slices', 'tasks'}
REJECT = 'REBUILD_EVAL_DATASET'

def assess(record: dict) -> str:
    absent = sorted(REQUIRED - record.keys())
    if absent:
        return "MISSING:" + ",".join(absent)
    contract_ok = not (sum(record["slices"].values()) != record["tasks"] or record["holdout"] == 0)
    return "PASS" if contract_ok else REJECT

valid_fx = {"case_id": 'CASO-ICA-050-1A', **{'tasks': 40, 'slices': {'normal': 25, 'edge': 10, 'adversarial': 5}, 'rubric_levels': {0, 1, 2, 3}, 'holdout': 10}}
